// Parse competitor pages from environment variable
// Format: JSON array of {company, url, type}

let pages;
try {
  const raw = process.env.COMPETITOR_PAGES_CONFIG;
  if (raw) {
    pages = JSON.parse(raw);
  } else {
    // Default sample pages for testing (replace with real ones)
    pages = [
      {
        "company": "Example Rival",
        "url": "https://example.com",
        "type": "homepage",
        "note": "Replace this with a real competitor URL"
      }
    ];
  }
} catch (e) {
  throw new Error(`Could not parse COMPETITOR_PAGES_CONFIG: ${e.message}. Expected a JSON array.`);
}

if (!Array.isArray(pages) || pages.length === 0) {
  throw new Error('COMPETITOR_PAGES_CONFIG must be a non-empty JSON array');
}

console.log(`Loaded ${pages.length} competitor page(s) to monitor`);

return pages.map((page, index) => ({
  json: {
    ...page,
    page_index: index,
    check_id: `check_${Date.now()}_${index}`,
    fetch_at: new Date().toISOString(),
  }
}));

// Strip HTML and normalise page content to plain text
const pageData = $input.first().json;
const competitorMeta = $('Load Competitor Pages Config').first().json;

// Get the HTML body
let html = typeof pageData === 'string' ? pageData : JSON.stringify(pageData);

// Strip HTML tags
let text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')  // remove scripts
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')    // remove styles
  .replace(/<[^>]+>/g, ' ')                             // remove all HTML tags
  .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')      // decode entities
  .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"').replace(/&#39;/g, "'")
  .replace(/\s+/g, ' ')                                 // collapse whitespace
  .trim();

// Truncate to avoid excessive storage/AI costs
const MAX_CHARS = 8000;
if (text.length > MAX_CHARS) {
  text = text.substring(0, MAX_CHARS) + '... [truncated]';
}

// Create a hash for change detection
let hash = 0;
for (let i = 0; i < text.length; i++) {
  hash = ((hash << 5) - hash) + text.charCodeAt(i);
  hash |= 0;
}
hash = Math.abs(hash).toString(36);

return [{
  json: {
    company: competitorMeta.company,
    url: competitorMeta.url,
    page_type: competitorMeta.type,
    content_text: text,
    content_hash: hash,
    char_count: text.length,
    captured_at: new Date().toISOString(),
    check_id: competitorMeta.check_id,
  }
}];

// Retrieve the previous snapshot for this URL
// BASIC STACK: We store previous snapshot in memory (in-workflow state via global variable)
// For persistent storage, use Google Sheets or PostgreSQL

// In production: replace this stub with a Google Sheets or DB lookup
// For demo purposes, we simulate a previous snapshot

const current = $input.first().json;

// Simulate a previous snapshot (in production: read from storage)
// If the URL has never been seen, previousHash will be null and we'll store the first snapshot
const simulatedPreviousText = `Previous version of ${current.company} ${current.page_type} page. Pricing starts at $49/month.`;
let simulatedPreviousHash = 0;
for (let i = 0; i < simulatedPreviousText.length; i++) {
  simulatedPreviousHash = ((simulatedPreviousHash << 5) - simulatedPreviousHash) + simulatedPreviousText.charCodeAt(i);
  simulatedPreviousHash |= 0;
}
simulatedPreviousHash = Math.abs(simulatedPreviousHash).toString(36);

// TODO (production): Query your storage here
// const previousSnapshot = await queryGoogleSheets(current.url);
const previousSnapshot = {
  content_text: simulatedPreviousText,
  content_hash: simulatedPreviousHash,
  captured_at: new Date(Date.now() - 6 * 60 * 60 * 1000).toISOString(),
};

const hasChanged = previousSnapshot.content_hash !== current.content_hash;
const diffLength = Math.abs(current.content_text.length - previousSnapshot.content_text.length);

console.log(`${current.company} ${current.page_type}: hasChanged=${hasChanged}, hashDiff=${previousSnapshot.content_hash}→${current.content_hash}`);

return [{
  json: {
    ...current,
    previous_text: previousSnapshot.content_text,
    previous_hash: previousSnapshot.content_hash,
    previous_captured_at: previousSnapshot.captured_at,
    has_changed: hasChanged,
    diff_length: diffLength,
    is_first_snapshot: !previousSnapshot.content_hash,
  }
}];

// Prepare the change data for AI analysis
const item = $input.first().json;

// Create a simple text diff (first/last differences)
const prevWords = new Set(item.previous_text.split(' '));
const currWords = new Set(item.content_text.split(' '));

const addedWords = [...currWords].filter(w => !prevWords.has(w)).slice(0, 50).join(', ');
const removedWords = [...prevWords].filter(w => !currWords.has(w)).slice(0, 50).join(', ');

const changeDescription = `
COMPANY: ${item.company}
PAGE TYPE: ${item.page_type}
URL: ${item.url}

PREVIOUS CONTENT (first 1000 chars):
${item.previous_text.substring(0, 1000)}

CURRENT CONTENT (first 1000 chars):
${item.content_text.substring(0, 1000)}

NEW WORDS/PHRASES: ${addedWords.substring(0, 300)}
REMOVED WORDS/PHRASES: ${removedWords.substring(0, 300)}
`.trim();

return [{
  json: {
    mode: 'competitor',
    items: [{
      id: item.check_id,
      text: changeDescription,
      metadata: {
        company: item.company,
        page_type: item.page_type,
        url: item.url,
        previous_hash: item.previous_hash,
        new_hash: item.content_hash,
      }
    }],
    // Pass through for later use
    _snapshot: item,
  }
}];

// Format the competitor change notification
const classifierOutput = $input.first().json;
const snapshot = $('Prepare Change for AI Analysis').first().json._snapshot;
const result = classifierOutput.results?.[0] || {};
const cls = result.classification || {};

const importanceEmoji = cls.importance_score >= 8 ? '🚨' : cls.importance_score >= 6 ? '⚠️' : 'ℹ️';

const body = `
${importanceEmoji} **Competitor Change Detected**

**Company:** ${snapshot.company}
**Page:** ${snapshot.page_type} — ${snapshot.url}
**Importance:** ${cls.importance_score}/10
**Change type:** ${cls.change_type || 'unknown'}

**Possible reason:**
${cls.possible_reason || 'Unknown'}

**Product impact:**
${cls.product_impact || 'See details'}

**Recommended response:**
${cls.recommended_response || 'Review the change and assess impact'}

**Detected at:** ${snapshot.captured_at}
`.trim();

return [{
  json: {
    channel: process.env.NOTIFICATION_CHANNEL || 'email',
    title: `${importanceEmoji} Competitor change: ${snapshot.company} ${snapshot.page_type}`,
    body,
    urgency: cls.importance_score >= 8 ? 'high' : 'medium',
    metadata: {
      company: snapshot.company,
      url: snapshot.url,
      importance_score: cls.importance_score,
      change_type: cls.change_type,
    }
  }
}];

// Save new snapshot (basic stack: log; advanced: write to DB/Sheets)
const snapshot = $input.first().json;
console.log(`Snapshot saved for ${snapshot.company} ${snapshot.page_type}: hash=${snapshot.content_hash}`);
// TODO (production): Write snapshot to Google Sheets or PostgreSQL
return [{ json: { saved: true, company: snapshot.company, hash: snapshot.content_hash } }];

// Below threshold — log and skip notification
const classifierOutput = $input.first().json;
const result = classifierOutput.results?.[0] || {};
console.log(`Change below threshold: importance=${result.classification?.importance_score || 'unknown'} < ${process.env.COMPETITOR_CHANGE_IMPORTANCE_THRESHOLD || 6}`);
return [{ json: { skipped: true, reason: 'below_threshold', importance: result.classification?.importance_score } }];
